			if (builder.applyVipBonus.HasValue)
			{
				request.applyVipBonus = new OptionalBool { HasValue = true, Value = builder.applyVipBonus.Value };
			}

			if (builder.currencies != null && builder.currencies.Count > 0)
			{
				request.currencies = new OptionalMapOfLong
				{
					HasValue = true,
					Value = new MapOfLong(builder.currencies)
				};
			}

			if (builder.currencyProperties != null && builder.currencyProperties.Count > 0)
