						.Select(p => new AutogeneratedModels.CurrencyProperty { name = p.name, value = p.value })
						.ToArray();
				}
				request.currencyProperties = new AutogeneratedModels.OptionalMapOfArrayOfCurrencyProperty
				{
					HasValue = true,
					Value = currencyPropsMap
				};
			}

			if (builder.deleteItems != null && builder.deleteItems.Count > 0)
			{
				request.deleteItems = new AutogeneratedModels.OptionalArrayOfItemDeleteRequest
				{
					HasValue = true,
					Value = builder.deleteItems.Select(item => new AutogeneratedModels.ItemDeleteRequest
					{
						contentId = item.contentId,
						id = item.itemId
					}).ToArray()
				};
			}
			
			// Include deltas
			
			if (builder.newItems != null && builder.newItems.Count > 0)
			{
				request.newItems = new AutogeneratedModels.OptionalArrayOfItemCreateRequest
				{
					HasValue = true,
					Value = builder.newItems.Select(item => new AutogeneratedModels.ItemCreateRequest
					{
						contentId = item.contentId,
						properties = item.properties?.Select(kvp => new AutogeneratedModels.ItemProperty { name = kvp.Key, value = kvp.Value }).ToArray()
							?? Array.Empty<AutogeneratedModels.ItemProperty>()
					}).ToArray()
				};
			}
			
			// scopes
			
			if (!string.IsNullOrEmpty(transaction))
			{
				request.transaction = new OptionalString { HasValue = true, Value = transaction };
			}
			
			if (builder.updateItems != null && builder.updateItems.Count > 0)
			{
				request.updateItems = new AutogeneratedModels.OptionalArrayOfItemUpdateRequest
				{
					HasValue = true,
					Value = builder.updateItems.Select(item => new AutogeneratedModels.ItemUpdateRequest
					{
						contentId = item.contentId,
						id = item.itemId,
						properties = item.properties?.Select(kvp => new AutogeneratedModels.ItemProperty { name = kvp.Key, value = kvp.Value }).ToArray()
							?? Array.Empty<AutogeneratedModels.ItemProperty>()
					}).ToArray()
				};
			}

			return request;
		}

		public Promise<List<InventoryObject<TContent>>> ViewToItems<TContent>(InventoryView view, IEnumerable<string> filter = null) where TContent : ItemContent, new()
		{
			var filterSet = filter?.ToList();
			var typeName = ContentTypeReflectionCache.GetContentTypeName(typeof(TContent));

			return Promise.Sequence(view.items
				.Where(kvp => kvp.Key.StartsWith(typeName))
				.Where(kvp => filterSet?.Any(filterId => kvp.Key.StartsWith(filterId)) ?? true)
				.Select(kvp =>
			{
				return ContentApi.Instance
					.FlatMap(service => service.GetContent<TContent>(new ItemRef(kvp.Key)))
					.Recover(ex =>
					{
						if (ex is ContentNotFoundException)
						{
							return null;
						}
						throw ex;
					})
					.Map(content =>
					{
						if (content == null)
						{
							content = ScriptableObject.CreateInstance<TContent>();
							content.SetIdAndVersion(kvp.Key, Constants.Features.Content.CONTENT_DEPRECATED);
						}
						return kvp.Value
							.Select(item => new InventoryObject<TContent>
							{
								Id = item.id,
								Properties = item.properties,
								ItemContent = content,
								CreatedAt = item.createdAt,
								UpdatedAt = item.updatedAt,
								UniqueCode = (((item.id.GetHashCode() << 5) + item.id.GetHashCode()) ^ content.Id.GetHashCode())
							}).ToList();
					});
			}).ToList()).Map(itemGroups =>
			{
				return itemGroups.SelectMany(x => x).Where(x => x != null).ToList();
			});
		}

		public Promise<List<InventoryObject<TContent>>> GetItems<TContent>() where TContent : ItemContent, new()
		{
			// this is the same as running a getCurrent with a certain scope.
			var typeName = ContentTypeReflectionCache.GetContentTypeName(typeof(TContent));
			return GetCurrent(typeName).FlatMap(view => ViewToItems<TContent>(view));
		}

		public Promise<List<InventoryObject<TContent>>> GetItems<TContent>(params ItemRef<TContent>[] itemReferences) where TContent : ItemContent, new()
		{
			var idFilter = itemReferences.Select(r => r.Id).ToList();
			var scope = string.Join(",", idFilter);
			return GetCurrent(scope).FlatMap(view => ViewToItems<TContent>(view, idFilter));
		}

